const html = $json.data;

// Captura o bloco após "Detalhes do Produto"
const match = html.match(/Detalhes do Produto<\/h2>([\s\S]*?)<\/div>/);

if (!match) {
  return [{ json: { error: "Descrição não encontrada" } }];
}

let description = match[1];

// Remove tags HTML
description = description.replace(/<[^>]*>/g, '').trim();

return [{ json: { description } }];
